import argparse
from kafka import KafkaAdminClient, NewTopic

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--topic", required=True, help="Name of the topic to create")
    parser.add_argument("--partitions", type=int, default=1, help="Number of partitions for the topic")
    parser.add_argument("--replication-factor", type=int, default=1, help="Replication factor for the topic")
    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=["localhost:9092"])

    # Create a new topic with the specified configuration
    new_topic = NewTopic(name=args.topic, num_partitions=args.partitions, replication_factor=args.replication_factor)
    admin_client.create_topics([new_topic])

